"use client";

/**
 * Magic-link callback.
 *
 * Supabase is on the implicit flow: the link drops the user here with
 * tokens in the URL fragment (`#access_token=...&refresh_token=...`).
 * The fragment never reaches the server, so we parse it client-side
 * and hand the tokens to /auth/finalize — a same-origin route handler
 * that validates them via the API and sets HTTP-only cookies.
 *
 * Once finalize succeeds we hard-navigate (window.location) to `next`
 * rather than router.replace so middleware re-runs against the freshly
 * set cookies on the next request.
 */

import { Suspense, useEffect, useState } from "react";
import { useSearchParams } from "next/navigation";

type State = "exchanging" | "error";

function parseFragment(): Record<string, string> {
  const hash = typeof window !== "undefined" ? window.location.hash.slice(1) : "";
  return Object.fromEntries(new URLSearchParams(hash));
}

/**
 * `useSearchParams` opts the page out of static prerendering unless its
 * caller sits inside a Suspense boundary. Wrap the inner component so
 * `next build` can prerender a shell while the client hydrates and
 * reads the actual params.
 */
export default function CallbackPage() {
  return (
    <Suspense fallback={<CallbackShell label="Signing you in…" />}>
      <CallbackInner />
    </Suspense>
  );
}

function CallbackInner() {
  const params = useSearchParams();
  const queryNext = params.get("next");
  const [state, setState] = useState<State>("exchanging");
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const tokens = parseFragment();
    const access_token = tokens["access_token"];
    const refresh_token = tokens["refresh_token"];
    const expires_at = Number(tokens["expires_at"] ?? "0");

    if (!access_token || !refresh_token) {
      setError("missing_tokens");
      setState("error");
      return;
    }

    const next = queryNext && queryNext.startsWith("/") ? queryNext : "/data";

    fetch("/auth/finalize", {
      method: "POST",
      headers: { "content-type": "application/json" },
      body: JSON.stringify({ access_token, refresh_token, expires_at }),
    })
      .then(async (res) => {
        if (!res.ok) {
          const body = (await res.json().catch(() => null)) as
            | { error?: string }
            | null;
          throw new Error(body?.error ?? `finalize_${res.status}`);
        }
        window.location.replace(next);
      })
      .catch((err: Error) => {
        setError(err.message);
        setState("error");
      });
  }, [queryNext]);

  if (state === "error") {
    if (typeof window !== "undefined") {
      window.location.replace(`/signin?error=${encodeURIComponent(error ?? "unknown")}`);
    }
    return null;
  }

  return <CallbackShell label="Signing you in…" />;
}

function CallbackShell({ label }: { label: string }) {
  return (
    <div
      style={{
        flex: 1,
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        color: "#8a8d94",
        fontSize: 14,
        fontFamily: "var(--font-inter), sans-serif",
      }}
    >
      {label}
    </div>
  );
}
